import{_ as o,o as t,c as d,a2 as a}from"./chunks/framework.CW5cCyjm.js";const h=JSON.parse('{"title":"业务审批接入","description":"","frontmatter":{},"headers":[],"relativePath":"mango-docs/guides/business-integration/workflow-business-approval.md","filePath":"mango-docs/guides/business-integration/workflow-business-approval.md"}'),s={name:"mango-docs/guides/business-integration/workflow-business-approval.md"};function i(l,e,r,c,n,k){return t(),d("div",null,[...e[0]||(e[0]=[a(`<h1 id="业务审批接入" tabindex="-1">业务审批接入 <a class="header-anchor" href="#业务审批接入" aria-label="Permalink to &quot;业务审批接入&quot;">​</a></h1><h2 id="_1-适用场景" tabindex="-1">1. 适用场景 <a class="header-anchor" href="#_1-适用场景" aria-label="Permalink to &quot;1. 适用场景&quot;">​</a></h2><p>业务单据需要发起审批，审批结束后回写业务状态，并能在业务页面查看流程进度。</p><h2 id="_2-阅读顺序" tabindex="-1">2. 阅读顺序 <a class="header-anchor" href="#_2-阅读顺序" aria-label="Permalink to &quot;2. 阅读顺序&quot;">​</a></h2><table tabindex="0"><thead><tr><th>顺序</th><th>文档</th><th>关注点</th></tr></thead><tbody><tr><td>1</td><td><a href="./../../../mango/mango-platform/mango-workflow/README">Workflow 后端 README</a></td><td>流程定义、实例、任务、事件和配置</td></tr><tr><td>2</td><td><a href="./../../../mango-ui/packages/workflow/README">@mango/workflow README</a></td><td>流程页面、设计器、任务 API</td></tr><tr><td>3</td><td><a href="./../../../mango-ui/packages/workflow-business-example/README">Workflow Example README</a></td><td>业务接入示例和页面 key</td></tr><tr><td>4</td><td><a href="./../../capabilities/README#3-组合接入入口">能力地图：业务审批闭环</a></td><td>组合验证入口</td></tr></tbody></table><h2 id="_3-接入检查点" tabindex="-1">3. 接入检查点 <a class="header-anchor" href="#_3-接入检查点" aria-label="Permalink to &quot;3. 接入检查点&quot;">​</a></h2><table tabindex="0"><thead><tr><th>环节</th><th>检查点</th></tr></thead><tbody><tr><td>业务状态</td><td>业务单据状态区分草稿、审批中、通过、驳回、撤回等业务语义</td></tr><tr><td>流程定义</td><td>业务类型、流程 key、表单编码和版本关系清晰</td></tr><tr><td>发起审批</td><td>业务保存和流程发起的事务边界可解释，失败时能回滚或补偿</td></tr><tr><td>审批回调</td><td>监听流程完成、驳回、撤回等事件并回写业务状态</td></tr><tr><td>页面入口</td><td>业务详情页展示流程进度、当前任务和审批记录</td></tr><tr><td>返回入口</td><td>业务跳转审批任务详情时传 <code>returnPath</code>，审批完成或点返回能回到业务列表，不回退到 Mango 默认待办</td></tr><tr><td>权限</td><td>发起、审批、撤回、查看记录按业务角色和流程任务共同判断</td></tr></tbody></table><h2 id="_4-最小闭环" tabindex="-1">4. 最小闭环 <a class="header-anchor" href="#_4-最小闭环" aria-label="Permalink to &quot;4. 最小闭环&quot;">​</a></h2><ol><li>新建业务单据并保存为草稿。</li><li>发起审批后业务状态变为审批中。</li><li>审批人能在任务列表看到待办。</li><li>审批通过后业务状态变为通过。</li><li>业务详情页能看到流程实例和审批记录。</li></ol><h2 id="_5-常见失败" tabindex="-1">5. 常见失败 <a class="header-anchor" href="#_5-常见失败" aria-label="Permalink to &quot;5. 常见失败&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>优先检查</th></tr></thead><tbody><tr><td>发起审批后没有待办</td><td>流程定义版本、节点办理人表达式、当前租户和组织数据</td></tr><tr><td>业务状态不更新</td><td>事件监听、回写服务、业务 ID 与流程 businessKey 映射</td></tr><tr><td>审批通过后业务侧仍显示上一节点</td><td>是否误用 <code>workflow.task.completed</code> 同步当前任务；当前任务刷新应使用 <code>workflow.task.advanced</code> 或 <code>complete-result</code></td></tr><tr><td>审批页打开空白</td><td>前端 workflow 包是否引入，页面 key 是否注册，接口是否 401/403</td></tr><tr><td>驳回后业务不可再次提交</td><td>业务状态流转是否覆盖驳回到草稿或重新提交</td></tr><tr><td>退回后业务侧仍显示原审批节点</td><td>业务侧是否使用 <code>POST /workflow/tasks/return</code> 响应或 <code>workflow.task.advanced</code> 同步刷新后的 <code>currentTasks</code></td></tr><tr><td>多租户流程串数据</td><td>流程定义、实例、任务和业务表 tenantId 是否一致</td></tr></tbody></table><h2 id="_6-事件接入" tabindex="-1">6. 事件接入 <a class="header-anchor" href="#_6-事件接入" aria-label="Permalink to &quot;6. 事件接入&quot;">​</a></h2><p>业务模块可以通过 workflow 事件异步回写业务状态，也可以在审批页调用任务接口同步拿到刷新结果。选择方式如下：</p><table tabindex="0"><thead><tr><th>业务目标</th><th>推荐方式</th></tr></thead><tbody><tr><td>审批按钮点击后立即刷新当前节点、当前办理人和页面按钮状态</td><td>调用 <code>POST /workflow/tasks/complete-result</code></td></tr><tr><td>审批退回后立即刷新当前节点、当前办理人和页面按钮状态</td><td>调用 <code>POST /workflow/tasks/return</code></td></tr><tr><td>审批中同步下一节点办理人、业务列表当前节点、待办摘要</td><td>订阅 <code>workflow.task.advanced</code></td></tr><tr><td>审计刚完成的任务和办理意见</td><td>订阅 <code>workflow.task.completed</code></td></tr><tr><td>流程通过后回写业务通过状态</td><td>订阅 <code>workflow.process.completed</code></td></tr><tr><td>流程驳回后回写业务驳回状态</td><td>订阅 <code>workflow.process.rejected</code></td></tr></tbody></table><p><code>workflow.task.completed</code> 和 <code>workflow.task.advanced</code> 的差异：</p><table tabindex="0"><thead><tr><th>事件</th><th>当前任务表是否已刷新</th><th>适合用途</th></tr></thead><tbody><tr><td><code>workflow.task.completed</code></td><td>否</td><td>记录当前任务完成动作。</td></tr><tr><td><code>workflow.task.advanced</code></td><td>是</td><td>同步下一节点或退回目标节点、当前办理人和业务进度。</td></tr></tbody></table><p><code>POST /workflow/tasks/return</code> 会把当前任务退回到最近一个已完成的不同用户任务节点，或退回到 <code>targetTaskDefinitionKey</code> 指定的历史节点。串行流程可以不传目标节点；并行、多实例、重复审批节点或业务语义固定的流程，应在流程节点动作配置或业务审批页中显式传入 <code>targetTaskDefinitionKey</code>。接口返回结构与 <code>complete-result</code> 一致，业务侧应使用返回的 <code>currentTasks</code> 或订阅 <code>workflow.task.advanced</code> 刷新业务单据当前节点和当前办理人；退回不会发布 <code>workflow.task.completed</code>，也不会把流程状态改为驳回。</p><p>单体多实例、微服务或微服务多实例部署时，事件应按至少一次投递处理。业务订阅方使用 <code>eventId</code>、<code>processInstanceId + completedTaskId</code> 或业务主键构造幂等键，避免重复回写状态、重复发通知或重复生成待办摘要。</p><h2 id="_7-变更影响记录" tabindex="-1">7. 变更影响记录 <a class="header-anchor" href="#_7-变更影响记录" aria-label="Permalink to &quot;7. 变更影响记录&quot;">​</a></h2><ul><li><p>v2026.06.30-maven-1.0.1-admin-branding-cli-release 只对齐固定后端 Maven <code>1.0.1</code>、前端 npm 批次和 CLI/starter 版本锁；不改变业务审批发起、审批回调、状态回写、流程页面 key、后端公开 API、配置、菜单、权限、租户隔离、启动方式和运行时行为。业务项目应成组升级本发布批次的后端 <code>&lt;mango.version&gt;</code> 和前端 <code>@mango/*</code> 包，避免新旧前端依赖混装。</p></li><li><p>v2026.06.29-workflow-return-cli-db-release 发布工作流退回能力和前端聚合版本锁。既有审批发起、通过、驳回、撤回和事件订阅流程保持兼容；使用退回动作前，先完成资源同步并给角色授予 <code>workflow:task:return</code> 权限。</p></li></ul><p>部署配置示例：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">mango</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  event</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    outbox</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    transport</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">redis-stream</span></span></code></pre></div><h2 id="_7-验证命令" tabindex="-1">7. 验证命令 <a class="header-anchor" href="#_7-验证命令" aria-label="Permalink to &quot;7. 验证命令&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango/pom.xml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mango-platform/mango-workflow</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -am</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -F</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @mango/workflow</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -F</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @mango/workflow-business-example</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><p>模块验证入口：</p><ul><li><a href="./../../../mango/mango-platform/mango-workflow/README#10-验证方式">Workflow 验证方式</a></li><li><a href="./../../../mango-ui/packages/workflow/README#10-验证方式">Workflow Frontend 验证方式</a></li><li><a href="./../../../mango-ui/packages/workflow-business-example/README#10-验证方式">Workflow Example 验证方式</a></li></ul><h2 id="_8-关联规则" tabindex="-1">8. 关联规则 <a class="header-anchor" href="#_8-关联规则" aria-label="Permalink to &quot;8. 关联规则&quot;">​</a></h2><ul><li><a href="./../../../mango-pmo/rules/08-capability-docs">能力说明维护规范</a></li><li><a href="./../../../mango-pmo/rules/05-ai-delivery-quality">AI 交付质量规则</a></li></ul><h2 id="_9-变更影响记录" tabindex="-1">9. 变更影响记录 <a class="header-anchor" href="#_9-变更影响记录" aria-label="Permalink to &quot;9. 变更影响记录&quot;">​</a></h2><ul><li><p>PR #295 只治理 Issue #183 后端测试规范、Mockito 审计和 workflow core service 集成测试；不改变业务审批发起、审批回调、状态回写、流程页面 key、后端公开 API、配置、菜单、权限、租户隔离、启动方式和运行时行为。</p></li><li><p>Issue #233 明确审批任务完成后的流程推进时序：业务模块同步下一节点待办、当前办理人或业务状态时，使用 <code>workflow.task.advanced</code> 或 <code>POST /workflow/tasks/complete-result</code>；<code>workflow.task.completed</code> 只表示当前任务完成，不承诺当前任务快照已刷新。</p></li><li><p>Issue #296 新增审批退回能力：<code>POST /workflow/tasks/return</code> 使用 <code>workflow:task:return</code> 权限，支持退回到最近历史用户任务节点或 <code>targetTaskDefinitionKey</code> 指定历史节点，并返回刷新后的当前任务快照。退回语义和驳回终止不同；业务模块可用接口响应或 <code>workflow.task.advanced</code> 同步业务当前节点、当前办理人和待办摘要。</p></li><li><p>v2026.06.27-workflow-history-dialog-release 发布 <code>@mango/workflow@1.0.17</code>、<code>@mango/admin-shell@1.0.29</code>、<code>@mango/grid-widgets@1.0.6</code>、<code>@mango/workflow-business-example@1.0.16</code>、<code>@mango/admin@1.0.33</code> 和 <code>@mango/cli@1.0.46</code>，仅对齐工作流历史弹窗标题修复的 npm 物料、聚合包和 CLI/starter 版本锁；不改变业务审批发起、审批回调、状态回写、流程页面 key、后端公开 API、配置、菜单、权限、租户隔离、启动方式和运行时行为。</p></li><li><p>本次 PR 修复 <code>WorkflowInstanceHistoryDialog</code> 内部历史申请标题重复显示问题，并为 <code>WorkflowInstanceHistory</code> 增加 <code>showTitle</code> 展示开关。该开关默认 <code>true</code>，业务页面直接使用历史申请组件时标题行为不变；内置弹窗会关闭组件内部标题，只保留弹窗标题。此次变更不改变业务审批发起、审批回调、状态回写、流程页面 key、后端公开 API、配置、菜单、权限、租户隔离、启动方式和运行时行为。</p></li><li><p>Issue #275 修复标准审批任务详情页对流程定义管理接口的隐式依赖。办理人打开 <code>/workflow/task/detail</code> 或业务包装后的任务详情页时，页面只依赖任务详情、流程实例、业务申请、<code>formJson</code>、运行时变量、<code>renderConfig</code> 和可选运行时 <code>designerJson</code>；不再主动调用流程定义列表、详情或版本管理接口。业务项目不需要给普通审批办理人额外授予流程定义管理权限；若运行时详情未携带 <code>designerJson</code>，页面会降级展示审批记录，不阻断业务表单和审批操作。</p></li><li><p>v2026.06.27-system-component-release 同步发布 <code>@mango/workflow@1.0.16</code>、<code>@mango/workflow-business-example@1.0.15</code> 及其前端依赖批次，仅对齐 npm 物料和 CLI/starter 版本锁；不改变业务审批发起、审批回调、状态回写、流程页面 key、后端公开 API、配置、菜单、权限、租户隔离、启动方式和运行时行为。业务项目排查审批页面异常时，仍先确认前端包批次一致、页面 key 已注册、流程定义和任务数据有效。</p></li><li><p>本次 PR 调整内置审批任务详情页操作按钮栏布局：按钮栏只显示在左侧业务内容列下方并居中，右侧流程摘要栏下方不再显示操作区；内容较长时按钮栏仍在内容列底部粘性悬浮。此次变更不改变业务审批发起、审批回调、状态回写、流程页面 key、后端公开 API、配置、菜单、权限、租户隔离、启动方式和运行时行为。</p></li><li><p>PR #268 新增 <code>@mango/workflow</code> 可复用审批详情 UI 组件：<code>WorkflowLayout</code>、<code>WorkflowSidebar</code>、<code>WorkflowInstanceSummary</code>、<code>WorkflowInstanceProgress</code>、<code>WorkflowDefinitionGraph</code>、<code>WorkflowDefinitionGraphDialog</code>、<code>WorkflowInstanceHistory</code> 和 <code>WorkflowInstanceHistoryDialog</code>。业务审批详情页可以优先使用 <code>WorkflowLayout + WorkflowSidebar</code> 组合左侧业务内容和右侧流程信息；任务详情页已复用该组件组。此次变更不改变业务审批发起、审批回调、状态回写、流程页面 key、后端公开 API、配置、菜单、权限、租户隔离、启动方式和运行时行为。业务项目继续通过 <code>WorkflowBusinessApplyApi.create()</code> 与 <code>WorkflowProcessApi.start()</code> 发起流程，并在业务后端自行校验权限、快照和幂等。</p></li><li><p>本次 PR 新增流程定义 <code>startEntryVisible</code> 启动入口可见性。业务内嵌流程可声明为“仅业务内嵌”，从审批中心发起流程列表隐藏；业务审批发起、审批回调、状态回写、流程页面 key、权限、租户隔离和业务上下文启动方式不变。业务模块仍应通过 <code>WorkflowBusinessApplyApi.create()</code> 与 <code>WorkflowProcessApi.start()</code> 按 <code>definitionKey</code>、<code>businessType</code>、<code>businessKey</code> 发起，并继续自行校验业务权限、快照和幂等。</p></li><li><p>本次 PR 新增 <code>@mango/grid-widgets</code> 我的申请系统小组件，并新增 <code>GET /workflow/business-applies/my/summary</code> 当前登录人申请统计接口；我的申请列表默认同时展示业务申请记录和直接发起的流程实例，并按流程实例 ID 去重，带 <code>statuses</code> 状态筛选时使用业务申请分页数据源。业务项目接入工作台后，可通过 <code>system.my-process</code> 展示审核中、已完成、已驳回和已撤回申请概览，列表跳转复用现有 <code>/workflow/task/initiated</code> 页面。</p></li><li><p>Issue #264 发布 <code>@mango/workflow@1.0.14</code>、<code>@mango/workflow-business-example@1.0.13</code> 并随前端发布批次对齐 <code>@mango/admin-pages@1.0.11</code>、<code>@mango/system@1.0.10</code>；不改变业务审批发起、审批回调、状态回写、流程页面 key、公开 API、配置、权限、租户隔离、页面验收步骤、启动方式和运行时行为。本次仅同步发布锁和 package 边界，业务项目应成组升级同一批次前端包。</p></li><li><p>PR #241 支持业务回传路径：业务系统跳转审批任务详情时可通过 <code>returnPath</code>（可选 <code>returnQuery</code>）指定审批完成后或点“返回”的落点，任务详情页顶部返回按钮按 <code>returnPath</code> 回到业务列表，不带则兜底回 Mango 默认待办/已办；同时精简审批任务详情页布局（流程信息右移、操作按钮条贴底固定）。不改变业务审批发起、审批回调、状态回写、流程页面 key、权限、租户隔离、启动方式和运行时行为。业务项目接入时，跳转 <code>/workflow/task/detail?taskId=xxx&amp;returnPath=/业务列表</code> 即可让审批人返回业务上下文。</p></li><li><p>本次 PR 新增 <code>@mango/grid-widgets</code> 我的待办系统小组件，并新增 <code>GET /workflow/tasks/todo/summary</code> 待办统计接口；业务审批发起、审批回调、状态回写、流程页面 key、流程定义配置、租户隔离和页面验收步骤不变。业务项目接入工作台后，可通过 <code>system.my-todo</code> 展示待审批、待处理、待确认和已超时任务概览，列表跳转仍复用现有待办和抄送页面。</p></li><li><p>PR #222 对齐 <code>@mango/numgen</code>、<code>@mango/template</code>、<code>@mango/workflow</code> 内部依赖的 <code>@mango/system</code> 版本到本地最新发布物料集合；不改变业务审批发起、审批回调、状态回写、流程页面 key、公开 API、配置、权限、租户隔离、页面验收步骤、启动方式和运行时行为。业务项目应成组安装同一批次的本地 <code>@mango/*</code> tarball，避免新旧内部依赖混装导致安装解析失败。</p></li><li><p>PR #216 加固前端 <code>@mango/*</code> npm 包发布边界，非 CLI 包不再发布 <code>src</code> 等源码目录，并补充发布包 tarball 和业务消费 typecheck 基线；不改变业务审批发起、审批回调、状态回写、流程页面 key、权限、租户隔离、页面验收步骤、启动方式和运行时行为。业务项目应继续使用公开 package 入口和样式入口，升级到后续发布的新包版本后重新运行前端 typecheck。</p></li><li><p>PR #199 将工作流菜单、接口权限和默认资源声明纳入 Resource Registry 注入链路，并修正菜单码/权限码复用风险；不改变业务审批发起、审批回调、状态回写、流程页面 key、权限判断、租户隔离和页面验收步骤。清库重建或 1.0 rebase 升级后，排查工作流菜单、待办接口 403、流程定义或节点定义缺失时，需要同时确认 <code>AUTH_MENU</code>、<code>API_RESOURCE</code>、<code>WORKFLOW_CATEGORY</code>、<code>WORKFLOW_TEMPLATE_CATEGORY</code> 和 <code>WORKFLOW_NODE_DEFINITION</code> 声明同步成功。</p></li><li><p>PR #195 加固前端 <code>@mango/*</code> 包的 <code>exports</code>、<code>types</code> 和生成声明文件，使业务项目通过发布后的 <code>dist</code> 产物独立消费；不改变业务审批发起、审批回调、状态回写、流程页面 key、权限、租户隔离、页面验收步骤、启动方式和运行时行为。业务项目应继续使用公开 package 入口和 <code>./style.css</code>，不要依赖包内 <code>src</code> 路径。</p></li><li><p>PR #194 发布资源注册中心版本并升级 <code>@mango/workflow@1.0.11</code>、<code>@mango/workflow-business-example@1.0.11</code>、<code>@mango/admin@1.0.23</code>、<code>@mango/common@1.0.10</code>、<code>@mango/cli@1.0.34</code> 等前端包；不改变业务审批发起、审批回调、状态回写、流程页面 key、权限、租户隔离、页面验收步骤和运行时行为。业务升级时应成组升级前端 <code>@mango/*</code> 包并刷新后端 Mango <code>1.0.0-SNAPSHOT</code> 依赖。</p></li><li><p>PR #193 新增 <code>mango-resource</code> 注册中心并将工作流分类、模板分类、节点定义和消息模板默认数据迁移为资源声明同步；不改变业务审批发起、审批回调、状态回写、流程页面 key、权限、租户隔离和页面验收步骤。排查流程定义或节点定义缺失时，需要同时确认 <code>WORKFLOW_CATEGORY</code>、<code>WORKFLOW_TEMPLATE_CATEGORY</code> 和 <code>WORKFLOW_NODE_DEFINITION</code> 声明是否已同步。</p></li><li><p>PR #171 将流程定义列表作为角色数据权限业务接入样例，<code>workflow:definition:list</code> 可按显式数据权限过滤；不改变业务审批发起、审批回调、状态回写、页面 key 和租户隔离方式。</p></li><li><p>PR #153 Maven revision 支持只调整构建和发布版本解析，不改变业务审批的公开 API、配置、权限、租户、页面和运行时行为。</p></li><li><p>PR #157 支付异常单依赖环修复和 workflow API/core 边界收敛只调整内部 Bean 依赖，不改变业务审批接入的公开 API、配置、权限、租户、页面和运行时行为。</p></li><li><p>PR 本次持久化基线与 README 发布物料治理只补充业务开发查看 Mango 能力文档的入口，并让 npm 包携带 package README；不改变业务审批发起、审批回调、状态回写、流程页面 key、权限、租户隔离、启动和运行时行为。</p></li></ul>`,30)])])}const w=o(s,[["render",i]]);export{h as __pageData,w as default};
